// Entrada: body del webhook { message, history[], lang }
const input = $input.first().json;
const body = input.body || input;
const message = String(body.message || '').slice(0, 1000);
const history = Array.isArray(body.history) ? body.history.slice(-8) : [];
const lang = body.lang === 'en' ? 'en' : 'es';

// Catalogo REAL (compacto) servido por la web
const catalog = await this.helpers.httpRequest({
  url: 'https://web-bochile.onrender.com/data/catalog.min.json',
  json: true,
});

// ---- PRE-FILTRO DETERMINISTICO ----
// Un modelo chico no escanea confiable 235 props. Filtramos por codigo (tipo/ciudad/precio/tema)
// + scoring de texto/direccion (tolera "alem127" = "Alem 127") y le pasamos a la LLM ~20 candidatos.
function pickCandidates(msg) {
  const norm = (s) => (s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
  const squash = (s) => norm(s).replace(/[^a-z0-9]/g, '');
  const STOP = new Set(['me','mi','interesa','interesan','la','el','los','las','un','una','unos','unas','de','del','en','para','por','con','y','o','que','quiero','busco','buscando','necesito','hola','tienen','tenes','hay','algo','alguna','algun','sobre','propiedad','propiedades','info','informacion','cuanto','sale','vale','es','esta','estoy','al','veo','uno','ver','comprar','comprr','compra','venta','alquiler','disponible','disponibles','quisiera','gustaria','i','want','looking','for','the','an','of','in','do','you','have','about','property','house','need']);
  const tokens = (t) => [...new Set(norm(t).split(/[^a-z0-9]+/).filter((w) => w.length >= 2 && !STOP.has(w)))];
  function parseMaxPrice(t) {
    const km = t.match(/(\d{2,4})\s*(k|mil)\b/); if (km) return parseInt(km[1], 10) * 1000;
    if (/(hasta|menos|presupuesto|tope|por debajo|maximo|budget|under|max|\$|u\$s|usd|dolar)/.test(t)) {
      const m = t.replace(/[.\s]/g, '').match(/(\d{3,7})/); if (m) { let v = parseInt(m[1], 10); if (v < 1000) v *= 1000; return v; }
    }
    return null;
  }
  const t = norm(msg);
  let res = catalog.slice();
  if (/(depto|departamento|apartment|flat|semipiso|monoambiente)/.test(t)) res = res.filter((p) => /departamento|ph/i.test(p.type || ''));
  else if (/duplex/.test(t)) res = res.filter((p) => /duplex/.test(norm(p.type)));
  else if (/(lote|terreno|land|lot)/.test(t)) res = res.filter((p) => /lote|terreno/i.test(p.type || ''));
  else if (/(local|oficina|office|comercial)/.test(t)) res = res.filter((p) => /local|oficina/i.test(p.type || ''));
  else if (/(galpon|deposito|warehouse)/.test(t)) res = res.filter((p) => /galp/i.test(norm(p.type)));
  else if (/(campo|field|farm)/.test(t)) res = res.filter((p) => /campo/i.test(p.type || ''));
  else if (/(casa|house|home|chalet)/.test(t)) res = res.filter((p) => /casa/i.test(p.type || ''));
  if (/monte hermoso/.test(t)) res = res.filter((p) => /monte hermoso/i.test(p.city || ''));
  else if (/pehuen/.test(t)) res = res.filter((p) => /pehuen/i.test(norm(p.city)));
  else if (/sierra/.test(t)) res = res.filter((p) => /sierra/i.test(p.city || ''));
  else if (/bahia blanca/.test(t)) res = res.filter((p) => /bahia blanca/.test(norm(p.city)));
  const maxP = parseMaxPrice(t);
  if (maxP) res = res.filter((p) => p.price == null || p.price <= maxP);
  if (/(mar|playa|sea|beach|costa|dunas|frente al mar)/.test(t)) res = res.filter((p) => /mar|playa|dunas|costaner|monte hermoso|pehuen|sauce/.test(norm((p.title || '') + ' ' + (p.zone || '') + ' ' + (p.city || ''))));
  if (/(invers|invest|renta|pozo|rentab)/.test(t)) res = res.filter((p) => /invers|renta|pozo|oficina|local|galpon|profesional|comercial/.test(norm((p.title || '') + ' ' + (p.type || ''))));
  const toks = tokens(t);
  if (toks.length) {
    const scored = res.map((p) => {
      const haySpaced = norm((p.title || '') + ' ' + (p.zone || '') + ' ' + (p.city || '') + ' ' + (p.type || ''));
      const haySquash = squash((p.title || '') + ' ' + (p.zone || '') + ' ' + (p.city || ''));
      let s = 0;
      toks.forEach((w) => {
        if (haySpaced.includes(w)) s += (/^\d+$/.test(w) ? 3 : 1);
        if (w.length >= 4 && haySquash.includes(w)) s += (/\d/.test(w) ? 4 : 1);
      });
      return { p, s };
    });
    const hits = scored.filter((x) => x.s > 0).sort((a, b) => b.s - a.s);
    if (hits.length) res = hits.map((x) => x.p);
  }
  return res.slice(0, 20);
}

const lastUser = [...history].reverse().find((h) => h && h.role === 'user' && h.content);
let cands = pickCandidates(message);
if (cands.length === 0 && lastUser) cands = pickCandidates(lastUser.content + ' ' + message);
if (cands.length === 0) cands = catalog.slice(0, 20);

const sys = [
  lang === 'en'
    ? 'You are Camila, a real-estate advisor at Bochile (Bahia Blanca, Argentina, since 1970). Warm, professional, concise. Reply in English.'
    : 'Sos Camila, asesora de Bochile (inmobiliaria de Bahia Blanca, desde 1970). Calida, profesional y concisa. Trata al usuario de USTED (formal). Responde en espanol.',
  'Abajo tenes CANDIDATOS: propiedades REALES ya PRE-FILTRADAS por codigo para esta consulta. Solo podes recomendar de esa lista. NUNCA inventes propiedades, precios ni direcciones.',
  'IMPORTANTE: si en CANDIDATOS hay una propiedad que coincide con lo que pide el usuario (una calle, una zona, un tipo), DEBES ofrecerla — NO digas que no tenes nada. Elegi hasta 3 ids que mejor matcheen y devolvelos en "props".',
  'Si la consulta es un saludo o algo general donde ningun candidato aplica, props=[].',
  'No hay alquileres cargados (todos op="sale"). Si piden alquiler, avisa con honestidad y ofrece tomar sus datos por WhatsApp.',
  'Cuando tenga sentido, sugeri continuar por WhatsApp para coordinar con un asesor.',
  'Numeros de WhatsApp de Bochile (son los UNICOS validos; NUNCA inventes ni des otro): para VENTA, compra, tasacion o consulta general -> +54 9 291 577 0521 (Camila / Ventas). Para ALQUILERES -> +54 9 291 507 4095. Da SIEMPRE el que corresponda segun lo que pida el usuario, y nunca un telefono inventado.',
  'RESPONDE EXCLUSIVAMENTE en JSON valido: {"text": string, "props": string[]}. Nada fuera del JSON.',
  'CANDIDATOS (JSON): ' + JSON.stringify(cands),
].join('\n');

const messages = [{ role: 'system', content: sys }];
for (const h of history) {
  if (h && (h.role === 'user' || h.role === 'assistant') && h.content) {
    messages.push({ role: h.role, content: String(h.content).slice(0, 1000) });
  }
}
messages.push({ role: 'user', content: message });

return [{ json: { body: { model: 'gpt-4o-mini', temperature: 0.4, response_format: { type: 'json_object' }, messages } } }];

// Parsea la respuesta de OpenAI -> { text, props }
const res = $input.first().json;
let out = { text: '', props: [] };
try {
  const content = res.choices[0].message.content;
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  out.text = String(parsed.text || '').trim();
  out.props = Array.isArray(parsed.props) ? parsed.props.map(String).slice(0, 3) : [];
} catch (e) {
  out.text = '';
}
if (!out.text) out.text = 'Disculpe, tuve un inconveniente. Puede escribirnos por WhatsApp y lo atendemos enseguida.';
return [{ json: out }];
